export default function Loading() {
  return (
    <div className="gc-container py-8 animate-pulse">
      <div className="skeleton h-10 w-48 rounded-xl mb-3" />
      <div className="skeleton h-4 w-72 rounded-lg mb-8" />
      <div className="skeleton h-[500px] rounded-[28px] mb-8" />
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[1, 2, 3, 4].map((i) => (
          <div key={i} className="skeleton h-72 rounded-[22px]" />
        ))}
      </div>
    </div>
  );
}
